import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.CxZWPeXl.js";const g=JSON.parse('{"title":"Frequently Asked Questions (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"en/faq.md","filePath":"en/faq.md"}'),n={name:"en/faq.md"};function r(s,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="frequently-asked-questions-faq" tabindex="-1">Frequently Asked Questions (FAQ) <a class="header-anchor" href="#frequently-asked-questions-faq" aria-label="Permalink to &quot;Frequently Asked Questions (FAQ)&quot;">​</a></h1><blockquote><p>Encountering issues? Find answers here.</p></blockquote><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#login--accounts">Login &amp; Accounts</a></li><li><a href="#practice-sessions">Practice Sessions</a></li><li><a href="#evaluation-reports">Evaluation Reports</a></li><li><a href="#practice-history">Practice History</a></li><li><a href="#knowledge-assistant">Knowledge Assistant</a></li><li><a href="#administrator-features">Administrator Features</a></li><li><a href="#system--performance">System &amp; Performance</a></li><li><a href="#error-message-quick-reference">Error Message Quick Reference</a></li></ul><hr><h2 id="login-accounts" tabindex="-1">Login &amp; Accounts <a class="header-anchor" href="#login-accounts" aria-label="Permalink to &quot;Login &amp; Accounts&quot;">​</a></h2><h3 id="q-i-cannot-log-into-the-system" tabindex="-1">Q: I cannot log into the system? <a class="header-anchor" href="#q-i-cannot-log-into-the-system" aria-label="Permalink to &quot;Q: I cannot log into the system?&quot;">​</a></h3><p><strong>A:</strong> Please check the following items in order:</p><ol><li>Confirm you are using a company account (Google or Microsoft), not a personal account.</li><li>Confirm your account has been added to the system by an administrator.</li><li>Confirm your account status is &quot;Active&quot; (not &quot;Disabled&quot;).</li><li>Try clearing your browser cache and logging in again.</li><li>If the issue persists, contact your company administrator.</li></ol><h3 id="q-it-says-account-disabled-after-logging-in" tabindex="-1">Q: It says &quot;Account Disabled&quot; after logging in? <a class="header-anchor" href="#q-it-says-account-disabled-after-logging-in" aria-label="Permalink to &quot;Q: It says &quot;Account Disabled&quot; after logging in?&quot;">​</a></h3><p><strong>A:</strong> Your account has been disabled by an administrator. Please contact your administrator to change your account status back to &quot;Active&quot;.</p><h3 id="q-why-can-t-i-see-certain-features-like-admin-settings-or-the-knowledge-assistant-after-logging-in" tabindex="-1">Q: Why can&#39;t I see certain features (like admin settings or the knowledge assistant) after logging in? <a class="header-anchor" href="#q-why-can-t-i-see-certain-features-like-admin-settings-or-the-knowledge-assistant-after-logging-in" aria-label="Permalink to &quot;Q: Why can&#39;t I see certain features (like admin settings or the knowledge assistant) after logging in?&quot;">​</a></h3><p><strong>A:</strong> Feature visibility depends on your role permissions. Different roles have access to different features:</p><table tabindex="0"><thead><tr><th>Role</th><th>Available Features</th></tr></thead><tbody><tr><td>User</td><td>Conversation Practice, Evaluation Reports, Practice History, Dashboard</td></tr><tr><td>Admin</td><td>All above + User Management, Prompt Management, Stage Management, Knowledge Base Management</td></tr></tbody></table><p>If you need additional permissions, please contact an administrator to adjust your role settings.</p><h3 id="q-how-do-i-log-out" tabindex="-1">Q: How do I log out? <a class="header-anchor" href="#q-how-do-i-log-out" aria-label="Permalink to &quot;Q: How do I log out?&quot;">​</a></h3><p><strong>A:</strong> Click the logout icon in the top right corner of the page (an arrow pointing right), and confirm &quot;Are you sure you want to log out?&quot; to log out.</p><h3 id="q-how-do-i-switch-languages" tabindex="-1">Q: How do I switch languages? <a class="header-anchor" href="#q-how-do-i-switch-languages" aria-label="Permalink to &quot;Q: How do I switch languages?&quot;">​</a></h3><p><strong>A:</strong> Click the language switcher in the top right corner of the page and select your preferred language (Traditional Chinese / Vietnamese / English). The interface will update immediately after switching.</p><hr><h2 id="practice-sessions" tabindex="-1">Practice Sessions <a class="header-anchor" href="#practice-sessions" aria-label="Permalink to &quot;Practice Sessions&quot;">​</a></h2><h3 id="q-what-is-the-difference-between-random-persona-and-custom-persona" tabindex="-1">Q: What is the difference between &quot;Random Persona&quot; and &quot;Custom Persona&quot;? <a class="header-anchor" href="#q-what-is-the-difference-between-random-persona-and-custom-persona" aria-label="Permalink to &quot;Q: What is the difference between &quot;Random Persona&quot; and &quot;Custom Persona&quot;?&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Random Persona</td><td>The system generates a completely random customer persona (age, occupation, gender, income, etc.), ideal for quickly starting a practice session.</td></tr><tr><td>Custom Persona</td><td>You can specify some or all customer attributes (e.g., setting &quot;high income, married&quot;). Unspecified attributes are randomly filled by the system.</td></tr></tbody></table><h3 id="q-do-i-have-to-fill-out-all-fields-when-customizing-a-persona" tabindex="-1">Q: Do I have to fill out all fields when customizing a persona? <a class="header-anchor" href="#q-do-i-have-to-fill-out-all-fields-when-customizing-a-persona" aria-label="Permalink to &quot;Q: Do I have to fill out all fields when customizing a persona?&quot;">​</a></h3><p><strong>A:</strong> No. All fields are optional. You can set only the attributes you care about, and the AI will automatically fill in the rest. For example, if you only set &quot;age 35, married, high income&quot;, the system will automatically generate other attributes.</p><h3 id="q-does-the-mbti-personality-type-affect-the-ai-customer-s-behavior" tabindex="-1">Q: Does the MBTI personality type affect the AI customer&#39;s behavior? <a class="header-anchor" href="#q-does-the-mbti-personality-type-affect-the-ai-customer-s-behavior" aria-label="Permalink to &quot;Q: Does the MBTI personality type affect the AI customer&#39;s behavior?&quot;">​</a></h3><p><strong>A:</strong> Yes. The MBTI type significantly affects the AI customer&#39;s communication style, decision-making process, and reaction patterns. For example:</p><ul><li><strong>ISTJ</strong> (Logistician) customers will value data and details more.</li><li><strong>ENFP</strong> (Campaigner) customers will focus more on emotional connection.</li><li><strong>INTJ</strong> (Architect) customers will cut straight to the point.</li></ul><p>You can click the tooltip icon next to the &quot;Personality&quot; field in the persona setup panel to view detailed descriptions of each type.</p><h3 id="q-why-does-persona-generation-take-so-long" tabindex="-1">Q: Why does persona generation take so long? <a class="header-anchor" href="#q-why-does-persona-generation-take-so-long" aria-label="Permalink to &quot;Q: Why does persona generation take so long?&quot;">​</a></h3><p><strong>A:</strong> Persona generation usually takes a few seconds. If it takes longer than 30 seconds, it may be a network issue. Please try refreshing the page and try again.</p><h3 id="q-why-are-the-ai-customer-s-responses-unreasonable-during-the-conversation" tabindex="-1">Q: Why are the AI customer&#39;s responses unreasonable during the conversation? <a class="header-anchor" href="#q-why-are-the-ai-customer-s-responses-unreasonable-during-the-conversation" aria-label="Permalink to &quot;Q: Why are the AI customer&#39;s responses unreasonable during the conversation?&quot;">​</a></h3><p><strong>A:</strong> Possible reasons and suggestions:</p><ol><li><strong>Extreme persona settings</strong> — Try using a more reasonable combination of attributes.</li><li><strong>Unclear conversation context</strong> — Try communicating with more explicit expressions.</li><li><strong>Prompts need adjustment</strong> — Report to an administrator to review and adjust the AI Prompt settings.</li></ol><h3 id="q-why-can-t-i-send-a-message-and-it-shows-a-security-warning" tabindex="-1">Q: Why can&#39;t I send a message, and it shows a security warning? <a class="header-anchor" href="#q-why-can-t-i-send-a-message-and-it-shows-a-security-warning" aria-label="Permalink to &quot;Q: Why can&#39;t I send a message, and it shows a security warning?&quot;">​</a></h3><p><strong>A:</strong> The system has built-in content security detection. Messages containing the following content will be blocked:</p><ul><li>Personal Information (phone numbers, addresses, ID numbers, etc.)</li><li>Content attempting to bypass system security restrictions</li><li>Inappropriate or high-risk content</li><li>Malicious links</li></ul><p>Please modify your message and send it again. These checks ensure the safety of the practice environment.</p><h3 id="q-can-i-continue-an-unfinished-practice-session-later" tabindex="-1">Q: Can I continue an unfinished practice session later? <a class="header-anchor" href="#q-can-i-continue-an-unfinished-practice-session-later" aria-label="Permalink to &quot;Q: Can I continue an unfinished practice session later?&quot;">​</a></h3><p><strong>A:</strong> Yes. Unfinished sessions can be resumed via:</p><ul><li>The &quot;Continue Practice&quot; button in Recent Records on the dashboard.</li><li>The &quot;Continue Practice&quot; button in Practice History.</li></ul><p>When continuing, the AI customer will have a vague impression of the previous conversation.</p><h3 id="q-can-i-practice-with-the-exact-same-customer-again" tabindex="-1">Q: Can I practice with the exact same customer again? <a class="header-anchor" href="#q-can-i-practice-with-the-exact-same-customer-again" aria-label="Permalink to &quot;Q: Can I practice with the exact same customer again?&quot;">​</a></h3><p><strong>A:</strong> Yes. Click &quot;Retry&quot; in the dashboard or practice history to start a new conversation using the exact same customer persona settings. This is very helpful for comparing the effectiveness of different strategies.</p><h3 id="q-when-should-i-end-the-conversation" tabindex="-1">Q: When should I end the conversation? <a class="header-anchor" href="#q-when-should-i-end-the-conversation" aria-label="Permalink to &quot;Q: When should I end the conversation?&quot;">​</a></h3><p><strong>A:</strong> We recommend ending the session when:</p><ol><li>You have achieved your intended practice goals.</li><li>The AI customer expresses a desire to end the conversation (a system prompt will appear).</li><li>You feel you have reached the learning objective.</li><li>You want to view the current evaluation results.</li></ol><hr><h2 id="evaluation-reports" tabindex="-1">Evaluation Reports <a class="header-anchor" href="#evaluation-reports" aria-label="Permalink to &quot;Evaluation Reports&quot;">​</a></h2><h3 id="q-why-is-my-evaluation-report-stuck-generating" tabindex="-1">Q: Why is my evaluation report stuck generating? <a class="header-anchor" href="#q-why-is-my-evaluation-report-stuck-generating" aria-label="Permalink to &quot;Q: Why is my evaluation report stuck generating?&quot;">​</a></h3><p><strong>A:</strong> Report generation usually takes 30 seconds to 2 minutes. If it takes longer than 5 minutes:</p><ol><li>Try refreshing the page.</li><li>Wait a moment and check again.</li><li>If the issue persists, contact an administrator.</li></ol><p>Each section of the report (stage evaluation, comprehensive review, etc.) is generated independently, so some sections may finish before others.</p><h3 id="q-what-is-the-difference-between-comprehensive-review-and-line-by-line-feedback" tabindex="-1">Q: What is the difference between &quot;Comprehensive Review&quot; and &quot;Line-by-line Feedback&quot;? <a class="header-anchor" href="#q-what-is-the-difference-between-comprehensive-review-and-line-by-line-feedback" aria-label="Permalink to &quot;Q: What is the difference between &quot;Comprehensive Review&quot; and &quot;Line-by-line Feedback&quot;?&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Comprehensive Review</td><td>Overall analysis, including stage completion status, overall performance evaluation, improvement suggestions, etc.</td></tr><tr><td>Line-by-line Feedback</td><td>Detailed analysis for each conversation turn (your message + AI response), providing specific feedback on communication skills.</td></tr></tbody></table><p>We recommend reading the &quot;Comprehensive Review&quot; first for an overall understanding, then switching to &quot;Line-by-line Feedback&quot; to find specific conversational details to improve.</p><h3 id="q-what-are-ai-inner-thoughts" tabindex="-1">Q: What are &quot;AI Inner Thoughts&quot;? <a class="header-anchor" href="#q-what-are-ai-inner-thoughts" aria-label="Permalink to &quot;Q: What are &quot;AI Inner Thoughts&quot;?&quot;">​</a></h3><p><strong>A:</strong> AI Inner Thoughts show the AI&#39;s simulated psychological activities of the customer after receiving your message. This helps you understand the customer&#39;s true thoughts at each moment, allowing you to adjust your communication strategy next time.</p><h3 id="q-can-i-provide-feedback-if-i-m-not-satisfied-with-the-evaluation-results" tabindex="-1">Q: Can I provide feedback if I&#39;m not satisfied with the evaluation results? <a class="header-anchor" href="#q-can-i-provide-feedback-if-i-m-not-satisfied-with-the-evaluation-results" aria-label="Permalink to &quot;Q: Can I provide feedback if I&#39;m not satisfied with the evaluation results?&quot;">​</a></h3><p><strong>A:</strong> Yes. There is a rating function below each evaluation section:</p><ul><li><strong>Positive</strong> — Found the evaluation helpful (optional comment can be added).</li><li><strong>Neutral</strong> — Default state, no specific opinion.</li><li><strong>Negative</strong> — Feel the evaluation needs improvement (reason must be provided).</li></ul><p>Your feedback helps the system continuously optimize evaluation quality.</p><h3 id="q-why-does-it-say-did-not-reach-any-evaluation-stage" tabindex="-1">Q: Why does it say &quot;Did not reach any evaluation stage&quot;? <a class="header-anchor" href="#q-why-does-it-say-did-not-reach-any-evaluation-stage" aria-label="Permalink to &quot;Q: Why does it say &quot;Did not reach any evaluation stage&quot;?&quot;">​</a></h3><p><strong>A:</strong> This means the AI determined that your conversation did not meet the standards for even the first sales stage. Possible reasons:</p><ul><li>Too few conversation turns.</li><li>Insufficient ice-breaking/trust-building behavior.</li><li>Conversation deviated from the sales topic.</li></ul><p>We recommend reviewing the specific feedback in the Line-by-line evaluation for directions on improvement.</p><hr><h2 id="practice-history" tabindex="-1">Practice History <a class="header-anchor" href="#practice-history" aria-label="Permalink to &quot;Practice History&quot;">​</a></h2><h3 id="q-why-can-t-i-find-any-records-after-filtering" tabindex="-1">Q: Why can&#39;t I find any records after filtering? <a class="header-anchor" href="#q-why-can-t-i-find-any-records-after-filtering" aria-label="Permalink to &quot;Q: Why can&#39;t I find any records after filtering?&quot;">​</a></h3><p><strong>A:</strong> Please note the following:</p><ol><li>Confirm the date range is set correctly.</li><li>Try reducing the number of filter criteria.</li><li>Click &quot;Clear All&quot; to remove all filters and check if any records exist.</li><li>Confirm the criteria in the active filter tags match your expectations.</li></ol><p>If no records are found, it means no practice sessions occurred under those conditions.</p><h3 id="q-why-is-the-continue-practice-button-disabled" tabindex="-1">Q: Why is the &quot;Continue Practice&quot; button disabled? <a class="header-anchor" href="#q-why-is-the-continue-practice-button-disabled" aria-label="Permalink to &quot;Q: Why is the &quot;Continue Practice&quot; button disabled?&quot;">​</a></h3><p><strong>A:</strong> Only sessions with an &quot;In Progress&quot; status can be continued. If a session has ended (manually or automatically by the system), you can only use &quot;Retry&quot; to start a new conversation.</p><hr><h2 id="knowledge-assistant" tabindex="-1">Knowledge Assistant <a class="header-anchor" href="#knowledge-assistant" aria-label="Permalink to &quot;Knowledge Assistant&quot;">​</a></h2><h3 id="q-why-are-the-knowledge-assistant-s-answers-inaccurate-or-incomplete" tabindex="-1">Q: Why are the Knowledge Assistant&#39;s answers inaccurate or incomplete? <a class="header-anchor" href="#q-why-are-the-knowledge-assistant-s-answers-inaccurate-or-incomplete" aria-label="Permalink to &quot;Q: Why are the Knowledge Assistant&#39;s answers inaccurate or incomplete?&quot;">​</a></h3><p><strong>A:</strong> The quality of the Knowledge Assistant&#39;s answers depends on the following factors:</p><ol><li><strong>Knowledge Base Content</strong> — Answers are based on files uploaded by administrators. If the knowledge base lacks relevant information, the answer may not be precise enough.</li><li><strong>Problem Description</strong> — Try phrasing your question differently; this might yield better results.</li><li><strong>Content Freshness</strong> — If the information is outdated, please contact an administrator to update the knowledge base.</li></ol><blockquote><p>The Knowledge Assistant&#39;s answers are for reference only. Please refer to official company documents for actual operations.</p></blockquote><h3 id="q-why-can-t-i-see-the-knowledge-assistant-icon" tabindex="-1">Q: Why can&#39;t I see the Knowledge Assistant icon? <a class="header-anchor" href="#q-why-can-t-i-see-the-knowledge-assistant-icon" aria-label="Permalink to &quot;Q: Why can&#39;t I see the Knowledge Assistant icon?&quot;">​</a></h3><p><strong>A:</strong> Your account may lack read permissions for the knowledge base. Please contact an administrator to verify your permission settings.</p><h3 id="q-where-did-my-chat-history-go" tabindex="-1">Q: Where did my chat history go? <a class="header-anchor" href="#q-where-did-my-chat-history-go" aria-label="Permalink to &quot;Q: Where did my chat history go?&quot;">​</a></h3><p><strong>A:</strong> The Knowledge Assistant&#39;s chat history is stored locally in your browser. The following actions will cause the history to be cleared:</p><ul><li>Clearing browser data/cache.</li><li>Clicking the &quot;Clear Chat&quot; button.</li><li>Using private/incognito browsing mode.</li><li>Switching browsers or devices.</li></ul><hr><h2 id="administrator-features" tabindex="-1">Administrator Features <a class="header-anchor" href="#administrator-features" aria-label="Permalink to &quot;Administrator Features&quot;">​</a></h2><h3 id="q-why-did-batch-importing-users-fail" tabindex="-1">Q: Why did batch importing users fail? <a class="header-anchor" href="#q-why-did-batch-importing-users-fail" aria-label="Permalink to &quot;Q: Why did batch importing users fail?&quot;">​</a></h3><p><strong>A:</strong> Common reasons:</p><table tabindex="0"><thead><tr><th>Reason</th><th>Solution</th></tr></thead><tbody><tr><td>File is not in CSV format</td><td>Ensure it is saved as a .csv file.</td></tr><tr><td>CSV column order is incorrect</td><td>Download the template and fill it according to the template format.</td></tr><tr><td>Duplicate Emails</td><td>Ensure there are no duplicate emails.</td></tr><tr><td>Missing required fields</td><td>Check that all required data in each row is complete.</td></tr><tr><td>Company/Department code does not exist</td><td>Verify you are using the correct company and department codes.</td></tr></tbody></table><p>The system provides a detailed error report, including the line number and specific reason for each failed entry.</p><h3 id="q-when-do-changes-to-prompts-take-effect" tabindex="-1">Q: When do changes to Prompts take effect? <a class="header-anchor" href="#q-when-do-changes-to-prompts-take-effect" aria-label="Permalink to &quot;Q: When do changes to Prompts take effect?&quot;">​</a></h3><p><strong>A:</strong> After modifying a Prompt, you must &quot;Publish&quot; (activate) that version for it to take effect. Once effective:</p><ul><li><strong>New Conversations</strong> — Will immediately use the new Prompt version.</li><li><strong>Ongoing Conversations</strong> — Will not be affected and will continue using the previous version.</li></ul><h3 id="q-will-deleting-a-stage-affect-completed-practice-sessions" tabindex="-1">Q: Will deleting a stage affect completed practice sessions? <a class="header-anchor" href="#q-will-deleting-a-stage-affect-completed-practice-sessions" aria-label="Permalink to &quot;Q: Will deleting a stage affect completed practice sessions?&quot;">​</a></h3><p><strong>A:</strong> Deleting a stage will not affect the data of completed practice sessions, but it may affect how that stage is displayed in evaluation reports. It&#39;s recommended to confirm no ongoing sessions are using the stage before deleting it.</p><h3 id="q-how-do-i-restore-a-deleted-user" tabindex="-1">Q: How do I restore a deleted user? <a class="header-anchor" href="#q-how-do-i-restore-a-deleted-user" aria-label="Permalink to &quot;Q: How do I restore a deleted user?&quot;">​</a></h3><p><strong>A:</strong> The system uses a soft delete mechanism. Deleted user data remains in the database. To restore, please contact the system administrator or technical team.</p><hr><h2 id="system-performance" tabindex="-1">System &amp; Performance <a class="header-anchor" href="#system-performance" aria-label="Permalink to &quot;System &amp; Performance&quot;">​</a></h2><h3 id="q-why-is-the-system-loading-so-slowly" tabindex="-1">Q: Why is the system loading so slowly? <a class="header-anchor" href="#q-why-is-the-system-loading-so-slowly" aria-label="Permalink to &quot;Q: Why is the system loading so slowly?&quot;">​</a></h3><p><strong>A:</strong> We recommend checking the following:</p><ol><li>Is your network connection stable?</li><li>Are you using the latest version of a supported browser?</li><li>Try closing other resource-intensive tabs.</li><li>Clear your browser cache and try again.</li></ol><h3 id="q-it-says-server-error-occurred-please-try-again-later" tabindex="-1">Q: It says &quot;Server error occurred, please try again later&quot;? <a class="header-anchor" href="#q-it-says-server-error-occurred-please-try-again-later" aria-label="Permalink to &quot;Q: It says &quot;Server error occurred, please try again later&quot;?&quot;">​</a></h3><p><strong>A:</strong> This indicates a temporary anomaly in the backend service. Recommendations:</p><ol><li>Wait a few minutes and try again.</li><li>If the issue persists for over 30 minutes, contact an administrator or IT department.</li><li>Do not repeatedly retry, as this may increase server load.</li></ol><h3 id="q-which-browsers-are-supported-by-the-system" tabindex="-1">Q: Which browsers are supported by the system? <a class="header-anchor" href="#q-which-browsers-are-supported-by-the-system" aria-label="Permalink to &quot;Q: Which browsers are supported by the system?&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>Browser</th><th>Supported Versions</th></tr></thead><tbody><tr><td>Google Chrome</td><td>Latest Version</td></tr><tr><td>Microsoft Edge</td><td>Latest Version</td></tr><tr><td>Mozilla Firefox</td><td>Latest Version</td></tr><tr><td>Apple Safari</td><td>Latest Version</td></tr></tbody></table><p>We recommend using Chrome or Edge for the best experience.</p><hr><h2 id="error-message-quick-reference" tabindex="-1">Error Message Quick Reference <a class="header-anchor" href="#error-message-quick-reference" aria-label="Permalink to &quot;Error Message Quick Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error Message</th><th>Description</th><th>Handling Method</th></tr></thead><tbody><tr><td>Authentication failed, please log in and try again</td><td>Login session expired</td><td>Log in again</td></tr><tr><td>Unexpected access, please try again later or contact admin</td><td>Insufficient permissions</td><td>Verify account permissions, contact admin</td></tr><tr><td>Requests too frequent, please try again later</td><td>Operation rate limit exceeded</td><td>Wait a few minutes and try again</td></tr><tr><td>Server error occurred, please try again later</td><td>Backend service anomaly</td><td>Wait and retry or contact IT</td></tr><tr><td>Network connection error</td><td>Network interruption</td><td>Check network connection</td></tr><tr><td>Resource not found</td><td>The requested resource does not exist</td><td>Verify the operation target is correct</td></tr><tr><td>Operation failed</td><td>General operation anomaly</td><td>Retry or contact admin</td></tr><tr><td>Input data incorrect</td><td>Form validation failed</td><td>Check if the input content meets format requirements</td></tr><tr><td>Contains unsafe characters</td><td>XSS protection triggered</td><td>Remove special characters and retry</td></tr></tbody></table><hr><h2 id="still-have-questions" tabindex="-1">Still Have Questions? <a class="header-anchor" href="#still-have-questions" aria-label="Permalink to &quot;Still Have Questions?&quot;">​</a></h2><p>If the above FAQs cannot solve your problem:</p><ol><li>Contact your company&#39;s system administrator.</li><li>Submit a service request to the IT department.</li><li>Provide the following information to expedite troubleshooting: <ul><li>Your account email</li><li>The time the issue occurred</li><li>A detailed description of the issue</li><li>Screenshots (if any)</li><li>The complete content of the error message</li></ul></li></ol>',119)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
